namespace Forge.Api.Data.TrainingContent;

public class PayrollTraining : TrainingContentBase
{
    public PayrollTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payroll Overview",
            Slug = "payroll-overview",
            Summary = "What payroll offers: view your own pay stubs and tax forms, download PDFs, and how admins add records for you.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/account/pay-stubs"]""",
            Tags = """["payroll","account","pay-stubs","tax-documents"]""",
            ContentJson = """{"body":"## Payroll Overview\n\nPayroll lets every team member view their own pay and year-end tax forms without asking HR. You see your earnings, your deductions, and your take-home pay. If your company connects a payroll provider like QuickBooks Payroll, your records show up here automatically. Admins can also add records by hand.\n\n### Payroll Is an Optional Feature\n\nPayroll is turned off unless your company turns it on. Whether you see any payroll pages depends on how your workspace was set up.\n\n- When it is on, your Pay Stubs and Tax Documents pages show your records, and admins can add records for you.\n- When it is off (the usual default), the Account menu may still list Pay Stubs and Tax Documents, but the pages stay empty. Many shops run payroll entirely in QuickBooks or an outside service and never turn this on.\n\nIf your Pay Stubs page is blank and you expected records, payroll is probably turned off for your workspace. Ask an admin to turn it on, or check whether payroll is meant to live in your accounting software instead.\n\n### What's Included\n\nWhen payroll is on, it lives under **Account** in the sidebar with two pages:\n\n- **Pay Stubs** — Every pay period, listed newest first. Each row shows the pay date, the period it covers, gross pay, deductions, and net pay. Many stubs have a PDF you can download.\n- **Tax Documents** — Your year-end tax forms, such as a W-2 or 1099, sorted by tax year, each with a PDF to download.\n\n### Viewing Your Own Records\n\nYou can open your own records any time:\n\n1. Go to **Account → Pay Stubs** to see all your pay stubs, newest first.\n2. Go to **Account → Tax Documents** to see all your tax forms, by year.\n3. Click the download icon on any row that has a PDF to view or save it.\n\nYou only ever see your own records — never anyone else's pay.\n\n### How Admins Add Records\n\nThe upload tools are **not** on your Account pages. Admins, Managers, and Office Managers add payroll records from **Admin → Compliance**. Here's how:\n\n1. Open **Admin → Compliance**.\n2. Pick the person from the **Select User** menu. The panel then shows that one person's forms, ID documents, pay stubs, and tax documents — everything on file for them.\n3. Scroll to the Pay Stubs or Tax Documents section to see what's there and add new records.\n\n**You drop the PDF first.** The details form only appears after the file is in place:\n\n- **Adding a pay stub** — Drop one PDF (up to 10 MB) into the upload area. Once it lands, the form appears: pay date, period start, period end, gross pay, and net pay. Fill it in and click **Save Pay Stub**. Deductions are worked out for you as gross pay minus net pay.\n- **Adding a tax document** — Drop one PDF into the upload area. The form then asks for the document type (such as W-2 or 1099) and the tax year. Click **Save Tax Document**.\n\nWithout a PDF, no form appears — you can't record a stub or form without its file. Records added by hand show a gray 'Manual' label and can be deleted from the same panel. Records that came from your payroll provider show a blue 'Synced' label and can't be deleted.\n\n### How Payroll Connects to Other Features\n\n**Accounting:** When a payroll provider like QuickBooks Payroll is connected, your pay stubs and tax forms come in automatically. Those records are view-only and show the blue 'Synced' label. Admins can pull in the latest records at any time.\n\n**Your profile:** Pay stubs belong to your account. Admins review and manage them from the per-person panel under Admin → Compliance.\n\n**Files:** The PDF for each pay stub or tax form is kept in secure file storage and downloads straight to you.\n\n### Pay Stub Deductions\n\nA pay stub can list deductions in several groups:\n\n- **Taxes:** federal tax, state tax, Social Security, Medicare\n- **Insurance:** health, dental, vision, life, disability\n- **Savings:** 401(k), health savings account, flexible spending account\n- **Other:** union dues, garnishment or child support, and anything else\n\nDeductions show on the pay stub detail and add up to the Total Deductions shown in the table.\n\n### When to Use Payroll\n\n- To check your latest pay stub or double-check a deduction\n- To download a W-2 or 1099 at tax time\n- When an admin needs to add a corrected pay stub or tax form for someone\n- When setting up a payroll provider and checking that the records that came in look right","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payroll — Guided Tour",
            Slug = "payroll-walkthrough",
            Summary = "A quick tour of Account > Pay Stubs: what each column means, how to download a PDF, and where records come from.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/account/pay-stubs"]""",
            Tags = """["payroll","account","walkthrough"]""",
            ContentJson = """{"appRoute":"/account/pay-stubs","startButtonLabel":"Tour Payroll","steps":[{"element":".account-sidebar","popover":{"title":"Account Menu","description":"Find your own records here. Pay Stubs and Tax Documents are view-only. Click either one to switch between them.","side":"right"}},{"element":".pay-stubs__title","popover":{"title":"Pay Stubs Page","description":"See all your pay stubs, newest first. Each row is one pay period with its totals. If this page is blank and you expected records, payroll is probably turned off for your workspace — ask an admin to turn it on.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Reading the Table","description":"Each row shows the pay date, the period it covers, your gross pay, net pay, and deductions, plus where the record came from and a download button. Click a heading to sort by that column.","side":"top"}},{"element":"app-data-table","popover":{"title":"Where Records Come From","description":"You can't add records here — this page is view-only. Rows with a blue 'Synced' label come in from your payroll provider. Rows with a gray 'Manual' label are added by an admin from Admin → Compliance: they pick your name, drop the PDF first, then fill in the pay details and save.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payroll Field Reference",
            Slug = "payroll-field-reference",
            Summary = "A quick reference for every column, field, button, and rule on the Pay Stubs and Tax Documents pages.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/account/pay-stubs"]""",
            Tags = """["payroll","account","reference"]""",
            ContentJson = """{"title":"Payroll Field Reference","groups":[{"heading":"Pay Stubs — Table Columns","items":[{"label":"Pay Date","value":"The date you were paid. Sortable, and the table sorts by this newest-first to start."},{"label":"Period","value":"The stretch of time this pay covers, shown as a start and end date."},{"label":"Gross Pay","value":"Your total earnings before any deductions or taxes. Sortable."},{"label":"Net Pay","value":"Your take-home pay after all deductions. Sortable."},{"label":"Deductions","value":"Everything taken out, added up. This equals gross pay minus net pay. Sortable."},{"label":"Source","value":"Where the record came from: a blue 'Synced' label if it came from your payroll provider, a gray 'Manual' label if an admin added it."},{"label":"Actions","value":"A download button, shown only when the stub has a PDF. Click it to open the PDF in a new tab."}]},{"heading":"Pay Stub Details","items":[{"label":"Pay Period Start (required)","value":"The first day of the pay period this stub covers."},{"label":"Pay Period End (required)","value":"The last day of the pay period. Must be on or after the start date."},{"label":"Pay Date (required)","value":"The date the payment went out."},{"label":"Gross Pay (required)","value":"Total earnings before deductions. Must be more than zero."},{"label":"Net Pay (required)","value":"Take-home pay after deductions. Must be more than zero and no higher than gross pay."},{"label":"Total Deductions","value":"Worked out for you: gross pay minus net pay."},{"label":"Total Taxes","value":"The tax part of your deductions added up (federal, state, Social Security, and Medicare). Shows 0 on records an admin added by hand."},{"label":"Attached File","value":"An optional PDF of the pay stub you can download."},{"label":"Source","value":"Whether the record came from your payroll provider or was added by an admin. Set for you automatically."},{"label":"Provider Reference","value":"An ID your payroll provider uses to track a synced record. Blank for records an admin added by hand."}]},{"heading":"Pay Stub Deduction Details","items":[{"label":"Category (required)","value":"What the deduction is for, picked from the standard list such as a tax, an insurance premium, or a retirement contribution."},{"label":"Description","value":"A plain label for the deduction, like 'Federal Income Tax', 'Medical PPO Plan', or '401(k) Match'."},{"label":"Amount","value":"The dollar amount taken out for this line."}]},{"heading":"Pay Stub Deduction Categories","items":[{"label":"Federal Tax","value":"Federal income tax held back based on your W-4."},{"label":"State Tax","value":"State income tax held back based on your state form and where you work."},{"label":"Social Security","value":"Your share of Social Security tax."},{"label":"Medicare","value":"Your share of Medicare tax."},{"label":"Health Insurance","value":"Your share of the medical insurance premium."},{"label":"401(k)","value":"Your contribution to a 401(k) retirement plan."},{"label":"Dental","value":"Your dental insurance premium."},{"label":"Vision","value":"Your vision insurance premium."},{"label":"Health Savings Account","value":"Money you set aside in a health savings account, before tax."},{"label":"Flexible Spending Account","value":"Money you set aside in a flexible spending account, before tax."},{"label":"Life Insurance","value":"A life insurance premium you pay, on top of any your employer covers."},{"label":"Disability Insurance","value":"A short-term or long-term disability insurance premium."},{"label":"Union Dues","value":"Union membership dues taken out under your union agreement."},{"label":"Garnishment / Child Support","value":"Court-ordered garnishments, child support, or wage assignments."},{"label":"Other","value":"Any deduction that doesn't fit the categories above."}]},{"heading":"Tax Documents — Table Columns","items":[{"label":"Tax Year","value":"The calendar year the form covers, such as 2025. Sortable."},{"label":"Document Type","value":"The kind of form: W-2, W-2c (corrected), 1099-MISC, 1099-NEC, or Other. Sortable."},{"label":"Employer","value":"The employer name on the form. Shows a dash when there isn't one."},{"label":"Source","value":"A blue 'Synced' or gray 'Manual' label, the same as on pay stubs."},{"label":"Actions","value":"A download button, shown only when the form has a PDF."}]},{"heading":"Tax Document Details","items":[{"label":"Document Type (required)","value":"The kind of form: a W-2, a corrected W-2, a 1099-MISC, a 1099-NEC, or Other."},{"label":"Tax Year (required)","value":"The calendar year the form applies to, such as 2025. Must be a four-digit year."},{"label":"Employer Name","value":"The employer name on the form. May be blank on forms an admin added by hand."},{"label":"Attached File","value":"An optional PDF of the tax form you can download."},{"label":"Source","value":"Whether the form came from your payroll provider or was added by an admin. Same as pay stubs."},{"label":"Provider Reference","value":"An ID your payroll provider uses to track a synced form."}]},{"heading":"Tax Document Types","items":[{"label":"W-2","value":"Wage and Tax Statement. The standard year-end form showing your total wages, tips, and taxes withheld. Issued to regular employees."},{"label":"W-2c","value":"Corrected Wage and Tax Statement. Issued when the original W-2 had a mistake, like a wrong Social Security number or wrong amounts."},{"label":"1099-MISC","value":"Miscellaneous Income. Reports payments such as rent, royalties, and prizes over $600."},{"label":"1099-NEC","value":"Nonemployee Compensation. Reports payments of $600 or more to independent contractors and freelancers."},{"label":"Other","value":"Any tax form that doesn't fit the standard types, such as a state-specific form or a 1095 health-coverage form."}]},{"heading":"How Admins Add Records (Admin → Compliance)","items":[{"label":"Where it is","value":"Not on your Account pages. Admins, Managers, and Office Managers add records from Admin → Compliance. Your Account pages are view-only and never show upload controls."},{"label":"Select User menu","value":"On the compliance tab, pick a person here first. The panel then loads just that person's forms, ID documents, pay stubs, and tax documents."},{"label":"Drop the PDF first","value":"Drop the PDF into the upload area before any fields show up. The details form stays hidden until the file is in place — with no PDF, there's nothing to save. Accepts one PDF, up to 10 MB."},{"label":"Pay stub form","value":"Appears once the pay-stub PDF is in: pay date, period start, period end, gross pay, net pay, then Save Pay Stub. Marked as added by an admin."},{"label":"Tax document form","value":"Appears once the tax-form PDF is in: document type and tax year, then Save Tax Document. Marked as added by an admin."}]},{"heading":"Buttons and Actions","items":[{"label":"Download PDF","value":"Opens the pay stub or tax form as a PDF in a new tab. Only shown when the record has a file attached."},{"label":"Admin: Add Pay Stub","value":"On Admin → Compliance for the chosen person. Drop the PDF first, then enter the period dates, pay date, gross pay, and net pay, and click Save Pay Stub."},{"label":"Admin: Add Tax Document","value":"On Admin → Compliance for the chosen person. Drop the PDF first, then choose the document type and tax year, and click Save Tax Document."},{"label":"Admin: Delete Pay Stub","value":"An admin or Office Manager action on the compliance panel. Only records an admin added by hand can be deleted; the delete button doesn't appear on synced records."},{"label":"Admin: Delete Tax Document","value":"An admin or Office Manager action on the compliance panel. Only records added by hand can be deleted; synced records can't be."},{"label":"Admin: Sync Payroll","value":"Pulls in the latest records from the connected payroll provider. Only available when a provider is connected."}]},{"heading":"Validation Rules","items":[{"label":"Pay Period Start","value":"Required. Must be a real date."},{"label":"Pay Period End","value":"Required. Must be a real date on or after the start date."},{"label":"Pay Date","value":"Required. Must be a real date."},{"label":"Gross Pay","value":"Required. Must be a positive number."},{"label":"Net Pay","value":"Required. Must be positive and no higher than gross pay."},{"label":"Tax Year","value":"Required. Must be a four-digit year."},{"label":"Document Type","value":"Required. Must be one of the five types: W-2, W-2c, 1099-MISC, 1099-NEC, or Other."}]},{"heading":"Who Can Do What","items":[{"label":"Turning payroll on","value":"Payroll is off unless your company turns it on. While it's off, the Pay Stubs and Tax Documents pages load no records. An admin turns it on for the whole workspace."},{"label":"You (viewing your own)","value":"You can view and download your own pay stubs and tax forms only. You can't add, change, or delete anything."},{"label":"Admins, Managers, Office Managers","value":"From Admin → Compliance, they can view, add, and delete records that were added by hand for any person, and pull in the latest from the payroll provider."},{"label":"Everyone else","value":"Same as you — view your own records only."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payroll Knowledge Check",
            Slug = "payroll-quiz",
            Summary = "Check what you know about payroll: pay stubs, tax forms, deductions, and how admins add records.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/account/pay-stubs"]""",
            Tags = """["payroll","account","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pr1","text":"Where do you find your own pay stubs?","options":[{"id":"a","text":"Admin → Payroll → Pay Stubs"},{"id":"b","text":"Account → Pay Stubs in the sidebar","isCorrect":true},{"id":"c","text":"Dashboard → Payroll → View All"},{"id":"d","text":"Reports → Payroll → My Pay Stubs"}],"explanation":"Your pay stubs live under Account → Pay Stubs. Everyone can open their own records from the Account menu."},{"id":"pr2","text":"A pay stub shows gross pay of $3,200 and net pay of $2,450. What are the total deductions?","options":[{"id":"a","text":"$2,450"},{"id":"b","text":"$750","isCorrect":true},{"id":"c","text":"$3,200"},{"id":"d","text":"$5,650"}],"explanation":"Total deductions are gross pay minus net pay: $3,200 − $2,450 = $750. This is worked out for you."},{"id":"pr3","text":"A pay stub shows a blue 'Synced' label in the Source column. What does that mean?","options":[{"id":"a","text":"An admin added the stub by hand and checked it"},{"id":"b","text":"The stub came in automatically from your connected payroll provider","isCorrect":true},{"id":"c","text":"The stub's PDF has been downloaded and saved on your device"},{"id":"d","text":"The stub was sent to your personal tax software"}],"explanation":"A blue 'Synced' label means the record came in automatically from your payroll provider, such as QuickBooks Payroll. A gray 'Manual' label means an admin added it by hand."},{"id":"pr4","text":"Which of these is NOT a pay stub deduction category?","options":[{"id":"a","text":"Health Insurance"},{"id":"b","text":"401(k)"},{"id":"c","text":"Parking Benefit","isCorrect":true},{"id":"d","text":"Garnishment / Child Support"}],"explanation":"Payroll has set categories for taxes, insurance, savings like a 401(k), union dues, garnishments, and more. Parking Benefit isn't one of them — it would go under 'Other'."},{"id":"pr5","text":"You need your W-2 for tax filing. Where do you find it?","options":[{"id":"a","text":"Account → Tax Documents, for the year you need","isCorrect":true},{"id":"b","text":"Account → Pay Stubs → Annual Summary"},{"id":"c","text":"Admin → Reports → Tax Forms"},{"id":"d","text":"Account → Compliance Forms → Tax Documents"}],"explanation":"Your tax forms, like W-2s and 1099s, are under Account → Tax Documents. Click the download icon to get the PDF."},{"id":"pr6","text":"What's the difference between a W-2 and a W-2c?","options":[{"id":"a","text":"A W-2 is for full-time employees, a W-2c is for contractors"},{"id":"b","text":"A W-2 is the standard wage and tax form; a W-2c is a corrected one issued when the original had a mistake","isCorrect":true},{"id":"c","text":"A W-2 covers federal taxes, a W-2c covers state taxes"},{"id":"d","text":"A W-2 comes out quarterly, a W-2c is the yearly summary"}],"explanation":"A W-2c is a corrected W-2. It's issued when the original had a mistake, like a wrong Social Security number or wrong amounts."},{"id":"pr7","text":"An admin needs to add a pay stub for someone. Where do they do it, and in what order?","options":[{"id":"a","text":"On that person's Account → Pay Stubs page, using an 'Add Pay Stub' button"},{"id":"b","text":"At Admin → Compliance: pick the person, drop the PDF first, then fill in the pay date, period, gross, and net and save","isCorrect":true},{"id":"c","text":"At Admin → Compliance: fill in all the pay details first, then attach a PDF at the end if they want"},{"id":"d","text":"On a Reports → Payroll upload screen open to anyone signed in"}],"explanation":"Admins add records from Admin → Compliance — not the Account pages, which are view-only. They pick the person, drop the PDF first, and only then does the form for pay date, period, gross pay, and net pay appear. No PDF means no form to save."},{"id":"pr8","text":"Can you delete your own pay stubs or tax forms?","options":[{"id":"a","text":"Yes, you can delete any of your own records"},{"id":"b","text":"Yes, but only ones added by hand"},{"id":"c","text":"No — only admins and Office Managers can delete payroll records","isCorrect":true},{"id":"d","text":"Yes, but only after the tax year closes"}],"explanation":"You can view your own records but not change them. Only admins and Office Managers can add or delete payroll records, and records that came from a payroll provider can't be deleted at all."},{"id":"pr9","text":"What kind of tax form would you expect for an independent contractor?","options":[{"id":"a","text":"W-2"},{"id":"b","text":"W-2c"},{"id":"c","text":"1099-NEC","isCorrect":true},{"id":"d","text":"1099-MISC"}],"explanation":"Independent contractors get a 1099-NEC for payments of $600 or more. A 1099-MISC covers other income like rent and royalties, not contractor pay."},{"id":"pr10","text":"A pay stub has no download icon in the Actions column. What does that mean?","options":[{"id":"a","text":"The stub has been archived and can't be opened"},{"id":"b","text":"The stub doesn't have a PDF attached","isCorrect":true},{"id":"c","text":"You don't have permission to download this stub"},{"id":"d","text":"The file server is down and downloads are paused"}],"explanation":"The download icon only shows when a stub has a PDF attached. Some synced records don't include one, and records added by hand may have been saved without a file."}]}"""
        });

        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payroll — Advanced Reference",
            Slug = "payroll-reference",
            Summary = "Deeper reference: how admins add records, how automatic sync works, pay-stub fields and rules, and turning payroll on or off.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/account/pay-stubs"]""",
            Tags = """["payroll","reference","advanced"]""",
            ContentJson = """{"body":"## How Admins Add Records\n\nAdmins add records from **Admin → Compliance**, never from the view-only Pay Stubs or Tax Documents pages. The admin picks the person from the **Select User** menu first; the panel then narrows every section — forms, ID documents, pay stubs, and tax documents — to just that person.\n\n- **Who can do it:** Admins, Managers, and Office Managers, and only when payroll is turned on for the workspace.\n- **Drop the PDF first:** the details form stays hidden until a PDF is in the upload area. With no file, there's nothing to save — you can't create a record without its PDF. Accepts one PDF, up to 10 MB, kept in secure file storage.\n- **Pay stub details:** pay date, period start, period end, gross pay, net pay, then **Save Pay Stub**. Total deductions are worked out as gross minus net. Total taxes show as 0 on records added by hand, since the by-hand form doesn't break out each deduction.\n- **Tax document details:** document type (W-2, W-2c, 1099-MISC, 1099-NEC, or Other) and tax year, then **Save Tax Document**.\n- **Labeling:** records added by hand get a gray **Manual** label.\n- **Deleting:** only records added by hand can be deleted, and the delete button only shows on those. Synced records can't be deleted, and nothing is ever truly erased — it's just hidden from view.\n\n## Records Added by Hand vs. Automatic\n\nThe table fills up two ways: an admin adds a record by hand, or it comes in automatically from your payroll provider.\n\n- **Automatic:** an admin starts a sync from the panel. If no payroll provider is connected, nothing happens. Otherwise, for each active person linked to the provider, their pay stubs and tax forms are pulled in and marked with the blue **Synced** label.\n- **Started by hand only:** there's no scheduled job for payroll — an admin starts each sync when they want it. Synced records are view-only and can't be deleted.\n- **No duplicates:** sync checks what's already in from the provider and only brings in records that aren't there yet, so running it again won't create copies. It only adds records — it never changes or removes ones already synced.\n- **Taxes on sync:** total deductions add up every deduction; total taxes add up just the tax ones (federal, state, Social Security, and Medicare). Any deduction the provider sends that doesn't match a known category is filed under 'Other'.\n- **One person failing doesn't stop the rest:** if syncing one person hits a snag, it's logged and the sync moves on to everyone else.\n\n## Pay Stub Fields and Rules\n\n- **Pay stub:** period start, period end (on or after the start), pay date, gross pay (more than zero), net pay (more than zero and no higher than gross), the worked-out total deductions and total taxes, an optional PDF, where it came from, and a provider reference for synced records.\n- **Each deduction:** a category (one of the standard groups like a tax, insurance premium, retirement contribution, union dues, or garnishment), a plain description, and an amount.\n- **Tax document:** document type (W-2, W-2c, 1099-MISC, 1099-NEC, or Other), a four-digit tax year, an optional employer name (shown as a dash when blank), an optional PDF, where it came from, and a provider reference.\n- **Download button:** only shows when a record has a PDF. Synced records without a provider PDF, and by-hand records saved without a file, show no download button.\n\n## Turning Payroll On or Off\n\nPayroll is off unless an admin turns it on for the workspace.\n\n- **Off by default:** while it's off, the Pay Stubs and Tax Documents pages may still appear in the Account menu, but they load no records. An admin turns payroll on in the admin settings.\n- **Needs time tracking:** payroll relies on time tracking, so time tracking has to be on for payroll to work.\n- **No in-app payroll run:** payroll here is about viewing and bringing in records, not running payroll or figuring withholdings. That happens in QuickBooks Payroll or an outside service — this app never calculates payroll taxes.\n- **On top of that, who does what:** turning payroll on decides whether it exists for the workspace at all; from there, only admins, managers, and Office Managers can add, delete, or sync records. Everyone else can still view their own.","sections":[]}"""
        });

        Log.Information("Seeded Payroll training modules");
    }
}
